async function u({type:t,amount:r,transactionID:s,name:a,email:c,tier:i}){const e=await fetch("/api/stripe-checkout",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({type:t,amount:r,transactionID:s,name:a,email:c,tier:i})});if(!e.ok){const n=await e.json().catch(()=>null);throw new Error((n==null?void 0:n.message)||"Unable to create Stripe checkout session")}const o=await e.json();if(!o.url)throw new Error("Stripe checkout URL was not returned");return o.url}function h(t="ID"){return`${t}-${Math.random().toString(36).substr(2,9).toUpperCase()}`}export{u as f,h as g};
